def find_matching_brace(s: str, open_pos: int) -> int:
    depth = 0
    i = open_pos
    n = len(s)
    quote = None
    esc = False
    while i < n:
        ch = s[i]
        if quote:
            if esc:
                esc = False
            elif ch == "\\":
                esc = True
            elif ch == quote:
                quote = None
        else:
            if ch == '"' or ch == "'":
                quote = ch
            elif ch == "{":
                depth += 1
            elif ch == "}":
                depth -= 1
                if depth == 0:
                    return i
        i += 1
    return -1

