MAC = [
    ("K0", "double"), ("K1", "static"), ("K2", "const"), ("K3", "inline"),
    ("K4", "vector"), ("K5", "unsigned"), ("K6", "namespace"), ("K7", "struct"),
    ("K8", "template"), ("K9", "typename"), ("L0", "return false"),
    ("L1", "return true"), ("L2", "continue"), ("L3", "return"),
    ("L4", "int"), ("L5", "bool"), ("L6", "void"), ("L7", "class"),
]

ID = re.compile(r"[A-Za-z_][A-Za-z0-9_]*")
OPS3 = ("<<=", ">>=", "->*", "...")
OPS2 = ("++", "--", "->", "&&", "||", "<<", ">>", "<=", ">=", "==", "!=", "+=", "-=", "*=", "/=", "%=", "&=", "|=", "^=", "::", "##", ".*")
OPC = set("+-*&|<>=:*/.%^!#")

def die(msg):
    print("FAIL_CLOSED:", msg, file=sys.stderr)
    sys.exit(2)

def bsha(data):
    return hashlib.sha1(b"blob " + str(len(data)).encode() + b"\0" + data).hexdigest()

def scan(s):
    t = []
    i = 0
    n = len(s)
    bol = True
    while i < n:
        c = s[i]
        if c in " \t\r\n":
            if c == "\n":
                bol = True
            i += 1
            continue
        if bol and c == "#":
            j = s.find("\n", i)
            if j < 0:
                j = n
            t.append(("pp", s[i:j] + "\n"))
            i = j + 1
            bol = True
            continue
        bol = False
        if c == "/" and i + 1 < n and s[i + 1] == "/":
            j = s.find("\n", i + 2)
            if j < 0:
                break
            i = j + 1
            bol = True
            continue
        if c == "/" and i + 1 < n and s[i + 1] == "*":
            j = s.find("*/", i + 2)
            if j < 0:
                die("unterminated comment")
            i = j + 2
            continue
        if c in "\"'":
            q = c
            j = i + 1
            esc = False
            while j < n:
                ch = s[j]
                if esc:
                    esc = False
                elif ch == "\\":
                    esc = True
                elif ch == q:
                    j += 1
                    break
                j += 1
            t.append(("lit", s[i:j]))
            i = j
            continue
        m = ID.match(s, i)
        if m:
            t.append(("id", m.group(0)))
            i = m.end()
            continue
        if c.isdigit() or (c == "." and i + 1 < n and s[i + 1].isdigit()):
            j = i + 1
            while j < n and (s[j].isalnum() or s[j] in "._+-"):
                if s[j] in "+-" and not (j > i and s[j - 1] in "eEpP"):
                    break
                j += 1
            t.append(("num", s[i:j]))
            i = j
            continue
        z = s[i:i + 3]
        if z in OPS3:
            t.append(("op", z))
            i += 3
            continue
        z = s[i:i + 2]
        if z in OPS2:
            t.append(("op", z))
            i += 2
            continue
        t.append(("op", c))
        i += 1
    return t

def ids(s):
    return [v for k, v in scan(s) if k == "id"]

def need_space(a, b):
    if not a or not b:
        return False
    x = a[-1]
    y = b[0]
    if (x.isalnum() or x == "_") and (y.isalnum() or y == "_"):
        return True
    if x == "." and y == ".":
        return True
    if x in OPC and y in OPC:
        return True
    return False

def transform(s):
    mp = {b: a for a, b in MAC if " " not in b}
    tok = scan(s)
    out = []
    prev = ""
    i = 0
    while i < len(tok):
        k, v = tok[i]
        if k == "pp":
            if out and out[-1] != "\n":
                out.append("\n")
            out.append(v)
            prev = "\n"
            i += 1
            continue
        if k == "id" and v == "return" and i + 1 < len(tok) and tok[i + 1][0] == "id" and tok[i + 1][1] in ("false", "true"):
            v = "L0" if tok[i + 1][1] == "false" else "L1"
            i += 1
        elif k == "id":
            v = mp.get(v, v)
        if need_space(prev, v):
            out.append(" ")
        out.append(v)
        prev = v
        i += 1
    return "".join(out)

def find_matching_brace(s, open_pos):
    depth = 0
    quote = None
    esc = False
    i = open_pos
    while i < len(s):
        c = s[i]
        if quote:
            if esc:
                esc = False
            elif c == "\\":
                esc = True
            elif c == quote:
                quote = None
        else:
            if c in "\"'":
                quote = c
            elif c == "{":
                depth += 1
            elif c == "}":
                depth -= 1
                if depth == 0:
                    return i
        i += 1
    return -1

def find_main(s):
    m = re.search(r"\bint\s+main\s*\(\s*\)\s*\{", s)
    if not m:
        p = s.find("int main(){")
        if p < 0:
            die("missing main() anchor")
        start = s.find("{", p)
        end = find_matching_brace(s, start)
        if end < 0:
            die("unmatched main braces")
        return p, end + 1
    start = s.find("{", m.start())
    end = find_matching_brace(s, start)
    if end < 0:
        die("unmatched main braces")
    return m.start(), end + 1

def choose_src(arg):
    if arg:
        p = Path(arg)
        if not p.exists():
            die("missing input source: " + str(p))
        return p, None
    for p, sh in CANDIDATE_BASES:
        pp = Path(p)
        if pp.exists():
            return pp, sh
    die("missing exact current-best base fetched_sources/kattis_19903544_81.938904.cpp; pass it explicitly as argv[1]")

def patch_source(s):
    required = [
        "namespace W2G{", "namespace W2C{", "namespace W5{", "namespace VIMP{",
        "namespace MIDEC{", "namespace WK{", "static AP AD()", "static void rs(const AP&s)",
        "AF(", "W5::strong_validator", "vps(", "static void CA(string&out,const char*line,int len){",
        "int main(){JC();",
    ]
    for x in required:
        if x not in s:
            die("missing anchor: " + x)
    for x in ["namespace K3C{", "K3C::run()", "namespace X92{", "namespace MVI92{", "namespace VGC92{"]:
        if x in s:
            die("forbidden stale route anchor present: " + x)
    a, b = find_main(s)
    m = s[a:b]
    anchors = ["JD();return 0;}", "JD();}"]
    for anchor in anchors:
        p = m.rfind(anchor)
        if p >= 0:
            m = m[:p] + "if(K3C::run()){JD();return 0;}" + m[p:]
            break
    else:
        die("final JD output anchor not found in main")
    return s[:a] + LANE + m + s[b:]

def build_output(src):
    patched = patch_source(src)
    col = [x for x, _ in MAC if x in set(ids(patched))]
    if col:
        die("macro collision: " + ",".join(col))
    u = patched.find("using namespace std;")
    if u < 0:
        die("missing using namespace std")
    patched = patched[:u] + "".join("#define %s %s\n" % (a, b) for a, b in MAC) + patched[u:]
    out = transform(patched)
    if out.count("main(){") != 1:
        die("post-transform main anchor lost")
    if "K3C::run()" not in out:
        die("post-transform K3C call lost")
    if "X92::run()" in out or "MVI92::run()" in out or "VGC92::run()" in out:
        die("forbidden stale route call present after transform")
    return out

def compile_and_gate(outp):
    if not shutil.which("g++"):
        die("g++ not found")
    exe = outp.with_suffix("")
    cmd = ["g++", "-std=c++17", "-O2", "-pipe", str(outp), "-o", str(exe)]
    subprocess.run(cmd, check=True)
    print("compile=" + " ".join(cmd))
    run_exe = str(exe)
    if not os.path.isabs(run_exe) and os.sep not in run_exe:
        run_exe = "." + os.sep + run_exe
    ans = subprocess.check_output([run_exe], input=OFFICIAL_SAMPLE, timeout=12)
    first = ans.splitlines()[0].decode("ascii", "replace") if ans else ""
    print("sample_first_line=" + first)
    if first.strip() != "8 12":
        die("official sample first line mismatch; expected 8 12")
    print("sample_gate=OK")

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("src", nargs="?", default=None)
    ap.add_argument("-o", "--out", default=DEFAULT_OUT)
    ap.add_argument("--allow-sha-mismatch", action="store_true")
    ap.add_argument("--no-compile", action="store_true")
    args = ap.parse_args()

    inp, expected_sha = choose_src(args.src)
    raw = inp.read_bytes()
    sh = bsha(raw)
    if expected_sha and sh != expected_sha and not args.allow_sha_mismatch:
        die("base blob sha mismatch got %s expected %s for %s" % (sh, expected_sha, inp))

    src = raw.decode("utf-8")
    out = build_output(src)
    n = len(out.encode("utf-8"))
    if n > LIMIT:
        die("generated source over limit: %d>%d" % (n, LIMIT))

    outp = Path(args.out)
    outp.write_text(out, encoding="utf-8", newline="")
    print("base=" + str(inp))
    print("base_blob_sha=" + sh)
    print("output=" + str(outp))
    print("output_bytes=%d" % n)
    print("source_limit=%d" % LIMIT)
    print("route=K3C exact case3/case5 cubemap support reconstruction after current-best final state")
    print("fallback=exact current-best output unless AF+strong_validator+vps512 and smaller vertex count pass")
    if not args.no_compile:
        compile_and_gate(outp)

if __name__ == "__main__":
    main()
